// URLs por competidor por categoría. Para sumar/sacar URLs, editá este array.
//
// IMPORTANTE: SimilarWeb estima tráfico por URL pero la calidad varía mucho.
// URLs de muy bajo tráfico (<5k visitas/mes) pueden no devolver data.
//
// Categorías canónicas: 'Lavado', 'Refrigeración', 'Cocinas'.

const URLS = [
  // Drean (cambiar si las URLs reales son distintas)
  { competidor: 'Drean',           categoria: 'Lavado',         url: 'https://www.drean.com.ar/lavarropas' },
  { competidor: 'Drean',           categoria: 'Refrigeración', url: 'https://www.drean.com.ar/heladeras' },
  { competidor: 'Drean',           categoria: 'Cocinas',        url: 'https://www.drean.com.ar/cocinas' },

  // Electrolux
  { competidor: 'Electrolux',      categoria: 'Lavado',         url: 'https://www.tienda.electrolux.com.ar/grandes-electrodomesticos/lavarropas' },
  { competidor: 'Electrolux',      categoria: 'Refrigeración', url: 'https://www.tienda.electrolux.com.ar/grandes-electrodomesticos/heladeras' },
  { competidor: 'Electrolux',      categoria: 'Cocinas',        url: 'https://www.tienda.electrolux.com.ar/grandes-electrodomesticos/cocinas' },

  // Gafa
  { competidor: 'Gafa',            categoria: 'Lavado',         url: 'https://www.tienda.gafa.com.ar/grandes-electrodomesticos/lavarropas' },
  { competidor: 'Gafa',            categoria: 'Refrigeración', url: 'https://www.tienda.gafa.com.ar/grandes-electrodomesticos/heladeras' },
  { competidor: 'Gafa',            categoria: 'Cocinas',        url: 'https://www.tienda.gafa.com.ar/grandes-electrodomesticos/cocinas' },

  // Whirlpool
  { competidor: 'Whirlpool',       categoria: 'Lavado',         url: 'https://www.whirlpool.com.ar/electrodomesticos/lavarropas' },
  { competidor: 'Whirlpool',       categoria: 'Refrigeración', url: 'https://www.whirlpool.com.ar/electrodomesticos/heladeras' },
  { competidor: 'Whirlpool',       categoria: 'Cocinas',        url: 'https://www.whirlpool.com.ar/electrodomesticos/cocinas' },

  // Philco / Newsan (no tienen categoría 'Cocinas')
  { competidor: 'Philco (Newsan)', categoria: 'Lavado',         url: 'https://tiendanewsan.com.ar/electrodomesticos/lavado/lavarropas.html' },
  { competidor: 'Philco (Newsan)', categoria: 'Refrigeración', url: 'https://tiendanewsan.com.ar/electrodomesticos/heladeras-freezers-y-cavas.html' },
];

return [{
  json: {
    urls: URLS,
    fecha: new Date().toISOString().slice(0, 10),
  },
}];

// Match cada URL scrapeada con su {competidor, categoria} desde Set Config
// y normaliza a fila para competitor_categoria_web.

const items = $input.all();
const config = $('Set Config').first().json;
const fecha = config.fecha;

// Indexar por URL normalizada (sin protocolo, sin trailing slash, lowercase)
const normUrl = (u) => String(u || '')
  .toLowerCase()
  .replace(/^https?:\/\//, '')
  .replace(/^www\./, '')
  .replace(/\/+$/, '')
  .trim();

const byUrl = {};
for (const c of config.urls) {
  byUrl[normUrl(c.url)] = c;
}

const pick = (obj, keys) => {
  for (const k of keys) {
    if (obj?.[k] !== undefined && obj?.[k] !== null) return obj[k];
  }
  return null;
};
const toInt = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? Math.round(n) : null;
};
const toFloat = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const output = [];
for (const item of items) {
  const r = item.json;
  // El actor devuelve la URL en distintos campos según el shape.
  const rawUrl = String(
    pick(r, ['name', 'url', 'website', 'siteName', 'domain']) || ''
  );
  const key = normUrl(rawUrl);
  const meta = byUrl[key];
  if (!meta) continue;

  output.push({
    json: {
      fecha,
      competidor: meta.competidor,
      categoria: meta.categoria,
      url: meta.url,
      visitas_estimadas: toInt(pick(r, ['totalVisits', 'monthlyVisits', 'visits', 'estimatedVisits'])),
      bounce_rate: toFloat(pick(r, ['bounceRate', 'bounce_rate'])),
      pages_per_visit: toFloat(pick(r, ['pagesPerVisit', 'pages_per_visit', 'pagesPerView'])),
      avg_visit_duration: toFloat(pick(r, ['avgVisitDuration', 'avg_visit_duration', 'averageVisitDuration'])),
      source: 'apify_similarweb',
      raw: r,
    },
  });
}

return output;
